/// A simple utility to encode bytes as a hexadecimal string.
fn hex_encode(bytes: &[u8]) -> String {
    const HEX_CHARS: &[u8] = b"0123456789abcdef";
    let mut output = String::with_capacity(bytes.len() * 2);
    for &b in bytes {
        output.push(HEX_CHARS[(b >> 4) as usize] as char);
        output.push(HEX_CHARS[(b & 0x0F) as usize] as char);
    }
    output
}

/// The immutable core content of a CDU.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Payload {
    /// The raw byte data of the payload.
    pub data: Vec<u8>,
    /// A string identifier for the payload's type (e.g., "genesis/v1").
    pub payload_type: String,
}

impl Payload {
    /// Computes the SHA3-256 hash of the payload's canonical representation.
    #[must_use]
    pub fn hash(&self) -> [u8; 32] {
        let mut canonical = self.payload_type.as_bytes().to_vec();
        canonical.extend_from_slice(&self.data);
        hash_sha3_256(&canonical)
    }
}

/// Special payload type for the Genesis CDU, containing a node's identity.
