/// The complete Causal Data Unit, the atom of knowledge.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Cdu {
    /// The unique, deterministic, and permanent identifier.
    pub id_hlc: Vec<u8>,
    /// The immutable core content.
    pub payload: Payload,
    /// The cryptographic hash of the payload's canonical bytes.
    pub payload_hash: [u8; 32],
    /// The mutable context.
    pub metadata: Metadata,
    /// An append-only log of signatures.
    pub signatures: Vec<Signature>,
}

/// A collection of helper functions to construct and interpret specific CDU subtypes.
impl Cdu {
    /// Creates a new CDU with a given payload and metadata, generating its ID.
    #[must_use]
    pub fn new(
        payload: Payload,
        mut metadata: Metadata,
        hlc: &HybridLogicalClock,
        node_id: &[u8],
    ) -> Self {
        let payload_hash = payload.hash();
        let hlc_ts = hlc.new_timestamp();
        metadata.hlc_timestamp = hlc_ts;

        let mut id_input = hlc_ts.as_u64().to_be_bytes().to_vec();
        id_input.extend_from_slice(node_id);
        id_input.extend_from_slice(&payload_hash);

        let id_hlc = hash_sha3_256(&id_input).to_vec();

        Self {
            id_hlc,
            payload_hash,
            payload,
            metadata,
            signatures: Vec::new(),
        }
    }

    /// A performance-oriented convenience constructor for creating a `ConfigCDU`.
    /// This function is written to avoid any memory allocations by reordering
    /// operations to prevent cloning the `author_node`.
    #[must_use]
    pub fn new_config(
        settings: HashMap<String, serde_json::Value>,
        author_node: Vec<u8>,
        hlc: &HybridLogicalClock,
    ) -> Self {
        let config_payload = ConfigPayload { settings };
        let payload = config_payload.into_payload();
        let payload_hash = payload.hash();
        let hlc_ts = hlc.new_timestamp();

        // Generate the ID while we can still borrow `author_node`.
        let mut id_input = hlc_ts.as_u64().to_be_bytes().to_vec();
        id_input.extend_from_slice(&author_node);
        id_input.extend_from_slice(&payload_hash);
        let id_hlc = hash_sha3_256(&id_input).to_vec();

        // Now that hashing is done, we can move `author_node` into the metadata.
        let metadata = Metadata {
            author_node, // Move, no clone.
            context_refs: vec![],
            state: "active".to_string(),
            weight: 1.0,
            r_coordinate: 0.0,
            world_context: "NodeWorld".to_string(),
            hlc_timestamp: hlc_ts,
        };

        Self {
            id_hlc,
            payload_hash,
            payload,
            metadata,
            signatures: Vec::new(),
        }
    }

    /// Adds a signature to the CDU's append-only log.
    #[must_use]
    pub fn with_signature(mut self, signature: Signature) -> Self {
        self.signatures.push(signature);
        self
    }

    /// Returns true if this CDU is the Genesis CDU of the node.
    #[must_use]
    pub fn is_genesis(&self) -> bool {
        self.payload.payload_type == "genesis/v1"
    }

    /// Attempts to interpret the CDU as a `ConfigCDU`.
    /// Returns `None` if the payload type is not "config/v1" or if deserialization fails.
    pub fn as_config(&self) -> Option<ConfigPayload> {
        if self.payload.payload_type != "config/v1" {
            return None;
        }
        serde_json::from_slice(&self.payload.data).ok()
    }
}

